import React, { useMemo, useState } from 'react';
import Image from 'gatsby-image';
import { makeStyles } from '@material-ui/core/styles';
import Gallery from 'react-photo-gallery';
import FsLightbox from 'fslightbox-react';

const useStyles = makeStyles((theme) => ({
    galleryWrapper: {
        '& .fslightbox-slide-number-container': {
            '& .fslightbox-flex-centered': {
                marginLeft: '30px',
            },
        },
    },
}));

const GatsbyImage = ({
    index,
    onClick,
    photo,
    margin,
}) => (
    <div
        role="presentation"
        key={index}
        onClick={(event) => onClick({
            event,
            type: 'image_clicked',
        }, { index, photo })}
        style={{
            margin,
            height: photo.height,
            width: photo.width,
            cursor: 'zoom-in',
        }}
    >
        <Image
            fixed={typeof window === 'undefined' ? { src: {} } : undefined}
            fluid={photo.fluid}
            onError={(event) => onClick({
                event,
                type: 'image_error',
            }, { index, photo })}
        />
    </div>
);

const PhotoGallery = ({ images }) => {
    const classes = useStyles();
    const [isShowingLightbox, setIsShowingLightbox] = useState(false);
    const [lightboxPhotoIndex, setLightboxPhotoIndex] = useState(1);
    const [galleryPhotos, setGalleryPhotos] = useState([]);

    const photos = useMemo(() =>
        galleryPhotos.length ?
            galleryPhotos
            : images?.edges
                ?.filter((image) => image.node.image)
                ?.map((image) => {
                    const { small, original } = image?.node?.image?.childImageSharp || {};

                    return {
                        height: original.height,
                        width: original.width,
                        src: small.src,
                        srcSet: small.srcSet,
                        fluid: small,
                        largeSrc: image?.node?.image?.childImageSharp?.large?.originalImg || '',
                    };
                }), [images, galleryPhotos]);

    const sources = useMemo(
        () => photos.map((photo) => photo.largeSrc),
        [photos, galleryPhotos]
    );

    return (
        <div className={classes.galleryWrapper}>
            <Gallery
                onClick={({ event, type }, { index }) => {
                    // use hack to be able to use the same onClick function
                    // to handle multiple actions. This is horrible, but it's
                    // the only way since there's no support for it in the
                    // plugin API
                    if (type === 'image_clicked') {
                        setLightboxPhotoIndex(index + 1);
                        setIsShowingLightbox(!isShowingLightbox);
                    } else if (type === 'image_error') {
                        const newArr = [...photos];
                        newArr.splice(index, 1);
                        setGalleryPhotos(newArr);
                    }
                }}
                photos={photos}
                renderImage={GatsbyImage}
            />
            <FsLightbox
                exitFullscreenOnClose
                // disableLocalStorage
                toggler={isShowingLightbox}
                sources={sources}
                key={sources.length}
                slide={lightboxPhotoIndex}
            />
        </div>
    );
};

export default PhotoGallery;
