import React from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import { makeStyles } from '@material-ui/core/styles';
import { Typography } from '@material-ui/core';

// Components
import Layout from '../components/Layout';
import SEO from '../components/SEO';
import PhotoGallery from '../components/PhotoGallery';

const useStyles = makeStyles((theme) => ({
    titleText: {
        margin: '15px 0',
    },
}));

const PhotosPage = ({ location, images, title, description }) => {
    const intl = useIntl();
    const classes = useStyles();

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={intl.formatMessage({ id: title })}
                description={intl.formatMessage({ id: description })}
                ogImage={images?.edges?.[0].node?.image?.childImageSharp?.large?.src}
                keywords={[
                    intl.formatMessage({ id: title }),
                    intl.formatMessage({ id: 'seo_keywords.personal_blog' }),
                    intl.formatMessage({ id: 'seo_keywords.personal_projects' }),
                    intl.formatMessage({ id: 'seo_keywords.travels' }),
                    intl.formatMessage({ id: 'seo_keywords.developer' }),
                    intl.formatMessage({ id: 'seo_keywords.photos' }),
                ]}
            />
            <Typography
                className={classes.titleText}
                color="textPrimary"
                variant="h4"
            >
                {intl.formatMessage({ id: title })}
            </Typography>
            <Typography
                className={classes.titleText}
                color="textPrimary"
                variant="body1"
            >
                {intl.formatMessage({ id: description })}
            </Typography>
            <div>
                <PhotoGallery
                    images={images}
                />
            </div>
        </Layout>
    );
};

export default PhotosPage;
